questions.solution:
**Problem**: Every non-static inner class holds an **implicit reference** to its enclosing outer class instance. If the inner class object outlives the outer class, the outer class cannot be garbage collected — even if nothing else references it.

**Classic Android example:**
```java
class Activity {
    class AsyncTask extends Thread { // holds Activity reference!
        void run() { /* long operation */ }
    }
}
// If activity is destroyed but task is still running,
// Activity cannot be GC'd → memory leak
```

**Fix 1 — Make it static:**
```java
static class AsyncTask extends Thread { /* no outer ref */ }
```

**Fix 2 — Use WeakReference if outer access needed:**
```java
static class AsyncTask extends Thread {
    WeakReference<Activity> actRef;
    // Only access if actRef.get() != null
}
```

public class Stack<T> {
    private static class Node<T> {
        T data;
        Node<T> next;
        Node(T data, Node<T> next) { this.data = data; this.next = next; }
    }

    private Node<T> top;
    private int size;

    public void push(T item) {
        top = new Node<>(item, top);
        size++;
    }

    public T pop() {
        if (isEmpty()) throw new java.util.EmptyStackException();
        T item = top.data;
        top = top.next;
        size--;
        return item;
    }

    public T peek() {
        if (isEmpty()) throw new java.util.EmptyStackException();
        return top.data;
    }

    public boolean isEmpty() { return top == null; }
    public int size() { return size; }

    public static void main(String[] args) {
        Stack<Integer> s = new Stack<>();
        s.push(1); s.push(2); s.push(3);
        System.out.println(s.peek()); // 3
        System.out.println(s.pop());  // 3
        System.out.println(s.pop());  // 2
        System.out.println(s.size()); // 1
    }
}

